def build_cycle_list(values, pos):
    if not values: return None
    head = ListNode(values[0])
    curr = head
    cycle_node = head if pos == 0 else None
    for i in range(1, len(values)):
        curr.next = ListNode(values[i])
        curr = curr.next
        if i == pos: cycle_node = curr
    if pos != -1: curr.next = cycle_node
    return head

def __run_test(values, pos):
